-- 使用武器声音表格
-- 此时subtype表示武器的类型
-- param1 表示的是武器的动作, attack = 1, tool = 2
function SoundUtil.InitWeaponSound(lineData)
	local line = {}
	local k2 = WeaponAction.Tool

	local weapon_name = lineData["SubType"]
	local weapon_action = lineData["param1"]
	
	if weapon_action == 'attack' then
		k2 = WeaponAction.Attack
	elseif weapon_action == 'break' then
		k2 = WeaponAction.Broken
	elseif weapon_action == 'behit' then
		k2 = WeaponAction.BeHit
	elseif weapon_action == 'behitkill' then
		k2 = WeaponAction.BeHitKill
	end

	return weapon_name, k2, line
end

-- 场景背景音乐
-- 此时SubType存放的是场景id
function SoundUtil.InitSceneMusic(lineData)
	local line = {}
	
	local sceneSoundSubType = math.tointeger(lineData["SubType"])
	local param = math.tointeger(lineData["playType"]) or 0

	if sceneSoundSubType == SceneSoundSubType.BarrelBattle then
		--主线关卡和其他Scene组的param含义不同！！！
		local param1Str = lineData["param1"]
		if (string.contains(param1Str, '-')) then
			--关卡范围
			local Range1, Range2 = string.split_ii(param1Str,'-')
			param = {}
			param.min = Range1
			param.max = Range2
		elseif tonumber(param1Str) ~= nil then
			--指定关卡
			param = tonumber(param1Str)
		else
			--加入随机
			param = nil
		end
		
	end
	
	return sceneSoundSubType, param, line
end

--[[
14 		电锯丧尸
22      英雄派遣
4;2   	普通怪
4;3   	巨型丧尸
22  	废墟
4;9		狂暴首领

11;85     中立城市
11;1     王座
11;103  炮塔
]]
function SoundUtil.PlayWorldMusic(pointType, subType, param, pointIndex)
	if pointType == 14 then -- 电锯丧尸
		SoundUtil.PlayEffect(SoundAssets.Click_Butcher)
	elseif pointType == 22 then -- 废墟
		SoundUtil.PlayEffect(SoundAssets.Click_Container)
	elseif pointType == 4 then
		if subType == 2 then
			local index = math.random(1,3)
			local _randNum = Mathf.Random()
			if _randNum > 0.5 then
				SoundUtil.PlayEffect(SoundAssets.Click_Monster_Female .. tostring(index))
			else
				SoundUtil.PlayEffect(SoundAssets.Click_Monster_Male .. tostring(index))
			end
		elseif subType == 3 then -- 集结怪
			SoundUtil.PlayEffect(SoundAssets.Click_Gaint)
		elseif subType == 9 then -- 狂暴首领
			SoundUtil.PlayEffect(SoundAssets.Click_Worldboss)
		end
	elseif pointType == 11 then
		if subType ~= nil then
			if subType == 1 then  -- 王座
				SoundUtil.PlayEffect(SoundAssets.Click_Throne)
			elseif subType == 103 then -- 炮台
				SoundUtil.PlayEffect(SoundAssets.Click_Turret)
			else
				SoundUtil.PlayEffect(SoundAssets.Click_WorldCity)
			end
		end
	elseif pointType == 13 then
		if pointIndex ~= nil then
			local data = DataCenter.WorldPointManager:GetSamplePointInfoByIndex(pointIndex)
			if data and data.eventId then
				local template = DataCenter.DetectEventTemplateManager:GetDetectEventTemplate(data.eventId)
				if template then
					if template.type == DetectEventType.RESCUE or template.type == DetectEventType.DetectEventPickGarbage then
						SoundUtil.PlayEffect("world/effect_click_container")
					end
				end
			end
		end
	end
end

