-- 解析声音配置的每一行，主要是解析ID，SubType，param1, param2这几个字段
-- 其余的字段是惰性解析的
function ParseSoundLine(id, lineData)
	
	local k1,k2,v
	
	-- 声音大的分类
	local typeId = lineData['group']

	-- 根据不同类型的规则去进行解析
	-- 有些类型只有一个索引，有些类型是两级索引
	if typeId == SoundGroupId.Misc then
		k1,k2,v = SoundUtil.InitSystemSound(lineData)
		
	elseif typeId == SoundGroupId.UI then
		k1,k2,v = SoundUtil.InitUISound(lineData)
		
	elseif typeId == SoundGroupId.Gather then
		k1,k2,v = SoundUtil.InitLootSound(lineData)
		
	elseif typeId == SoundGroupId.Actor then
		k1,k2,v = SoundUtil.InitActorSound(lineData)
		
	elseif typeId == SoundGroupId.Weapon then
		k1,k2,v = SoundUtil.InitWeaponSound(lineData)
		
	elseif typeId == SoundGroupId.Scene then
		k1,k2,v = SoundUtil.InitSceneMusic(lineData)
		
	elseif typeId == SoundGroupId.Building then
		k1,k2,v = SoundUtil.InitBuildingMusic(lineData)
	
	elseif typeId == SoundGroupId.Item then
		k1,k2,v = SoundUtil.InitItemMusic(lineData)
	
	elseif typeId == SoundGroupId.Action then
		k1,k2,v = SoundUtil.InitActionMusic(lineData)

	elseif typeId == SoundGroupId.Button then
		k1,k2,v = SoundUtil.InitButtonEffect(lineData)

	elseif typeId == SoundGroupId.Hero then
		k1,k2,v = SoundUtil.InitHeroSound(lineData)
		
	end

	if k1 == nil then
		return
	end
	
	-- 设置原始声音id
	v.c_sound_id = id
	
	-- 加入到指定类型列表
	if soundTable[typeId] == nil then
		soundTable[typeId] = {}
	end

	local typeTable = soundTable[typeId]
	
	--单独处理场景音效
	--先以k1(SceneSoundSubType)存储各种情况下的音效
	--再以k2(PlayType)存储统一情况下的不同播放方式(Sequence or Random)的音效
	--对于SceneSoundSubType.BarrelBattle类型下，不用考虑k2这种播放方式，而是单独的播放策略：param1配了范围则范围内的关卡播放，没配则在所有没配的里随机一个
	if typeId == SoundGroupId.Scene then
		if typeTable[k1] == nil then
			typeTable[k1] = {}
		end
		if k1 ~= SceneSoundSubType.BarrelBattle then
			if typeTable[k1][k2] == nil then
				typeTable[k1][k2] = {}
			end
			table.insert(typeTable[k1][k2],v)
		else
			local typeK2 = type(k2)
			if typeK2 == "table" then
				for i = k2.min,k2.max do
					typeTable[k1][i] = v
				end
			elseif typeK2 == "number" then
				typeTable[k1][k2] = v
			else
				if typeTable[k1].RandomRange == nil then
					typeTable[k1].RandomRange = {}
				end
				table.insert(typeTable[k1].RandomRange,v)
			end
		end
		return
	end
	
	-- 一个索引和两个索引的情况
	if k2 == nil then
		typeTable[k1] = v
	else 
		if typeTable[k1] == nil then
			typeTable[k1] = {}
		end
		typeTable[k1][k2] = v
	end
	
	return
end

-- 初始化声音表格
function SoundUtil.InitSound()
	table.clear(soundTable)
	LocalController:instance():visitTable(TableName.C_Sound, ParseSoundLine)
	--local t
	--SoundUtil.SceneMusicTableProcess()
end

function SoundUtil.SceneMusicTableProcess() --场景音乐Table处理
	for k,v in pairs(soundTable[SoundGroupId.Scene]) do
		--local Range = string.split_ii_array(k,'-')  -- 配置表中是这样配置 例如 "300-305"
		--if table.count(Range) > 1  then
		if string.contains(k, '-') then
			local Range1, Range2 = string.split_ii(k,'-')  -- 配置表中是这样配置 例如 "300-305"
			if Range1 and Range2 then
				if Range2 < Range1 then return end  --右值小于左值，则区间不成立
				for i = Range1, Range2 do     --1是范围区间最小值，2是范围区间最大值
					soundTable[SoundGroupId.Scene][i] = v
				end
				soundTable[SoundGroupId.Scene][k] = nil   --移除表中类似300-305这样的键值对，让表只保留key为关卡Id，一一对应
			end
		end
	end
end

function SoundUtil.GetSoundInternal(v, soundList, playType)
	
    local length = table.length(soundList)
    if length <= 1 or playType == PlayType.None then
        return soundList[1]
    end

    if playType == PlayType.Random then
        local idx = math.random(length)
        return soundList[idx]
    end

    if playType == PlayType.Sequence then
        local lastIdxFromZero = v.curIdxFromZero or -1
        local curIdxFromZero = Mathf.Repeat(lastIdxFromZero + 1, length)
        v.curIdxFromZero = curIdxFromZero

        return soundList[curIdxFromZero + 1] -- to lua index 
    end

    return soundList[1]
end

-- 获取播放的声音名字
function SoundUtil.GetSoundName(v)
	local t_sound = TableName.C_Sound
	local playType = LocalController:instance():getValue(t_sound, v.c_sound_id, 'playType')

	-- 第一次的时候解析一次
	if v.soundListArray == nil then
		local soundListStr = LocalController:instance():getValue(t_sound, v.c_sound_id, 'soundList')
		if string.find(soundListStr, '|') == nil then
			v.soundListArray = soundListStr
		else
			v.soundListArray = string.split_ss_array(soundListStr, '|')
		end
	end

	-- 获取一个声音文件
	local soundName = v.soundListArray
	if type(v.soundListArray) == 'table' then
		soundName = SoundUtil.GetSoundInternal(v, v.soundListArray, playType)
	end
	
	return soundName
end

-- 最终播放一条声音数据
function SoundUtil.FinalPlaySound(v)
	local t_sound = TableName.C_Sound
	local soundType = v.soundType 
	local soundName = v.soundListArray
	local volume = 1
	
	if v.c_sound_id ~= nil then
		soundType = GetTableNumber(t_sound, v.c_sound_id, 'soundType', 1)
		--@liusiyang 不在代码中控制音量了
		--volume = GetTableNumber(t_sound, v.c_sound_id, 'Volume')
		--if volume <= 0 then
		--	volume = 1.0
		--else
		--	volume = tonumber(volume) or 1.0
		--end
		
		soundName = SoundUtil.GetSoundName(v)
	end
	
	-- 根据类型播放，到底是音乐还是音效
	if soundType == SoundType.Music then
		local curSoundName = CS_Sound:GetCurPlayMusicName()
		if curSoundName ~= soundName then
			CS_Sound:PlayBGMusicByName(soundName, volume)
		end
		return -1
	end
	
	-- 这个代码这么临时处理一下吧，否则修改的地方略多，播放英雄声音的时候，使用playsound
	if v.group == SoundGroupId.Hero then
		local soundAsset = "Assets/Main/Sound/Effect/" .. soundName .. ".ogg"
		local playId = CS_Sound:PlaySound(soundAsset, "Hero", nil, false)
		return playId
	end
	
	-- loop的简易处理
	-- 底层loop同时只能播放一个，这样我们必须要手动控制好
	local loop = false
	if v.c_sound_id ~= nil then
		loop = GetTableNumber(t_sound, v.c_sound_id, 'Loop')
		if loop == 1 then
			loop = true
			local group = GetTableNumber(t_sound, v.c_sound_id, 'group')
			if group ~= 1 then
				Logger.LogError('loop effect must be group = 1!!')
				return -1
			end
		else
			loop = false
		end
	end
	--Logger.Log("SUSoundUtils.FinalPlay" .. soundName)
	local playId = CS_Sound:PlayEffect(_ToID(soundName), loop, volume)
	return playId
end

