-- 播放loop的声音，这个要传groupName，因为一个Group中只能同时有一个Loop声音
-- 这个时候要传递完整的路径
function SoundUtil.PlayLoopSound(soundFullPath, groupName)
	if groupName == nil then groupName = SoundGround.LoopSound end
	local serialID = CS_Sound:PlaySound(soundFullPath, groupName, nil, true)
	SoundUtil.ResetGroupMute(groupName)
	return serialID
end

