-- 播放未归类的声音，未归类声音就靠一个id来表示唯一性
-- 此时可以获取一个音效的播放id，然后可以停止
function SoundUtil.PlaySoundById(soundId)
    --local cfg = LocalController:instance():getLine(TableName.C_Sound, soundId)
	local cfg = soundTable[SoundGroupId.Misc][soundId]
    if cfg == nil then
        Logger.LogError('SoundUtil:PlaySoundById error! cfg not exist! soundId:' .. soundId)
        return -1
    end
	
	local id = SoundUtil.FinalPlaySound(cfg)
	return id
end

-- 播放第一次拾取声音
function SoundUtil.PlayFirstGatherSound(gatherId)
		
	local soundtype = GetTableNumber(TableName.PVETriggerGather, gatherId, 'soundtype')
	if soundtype <= 0 then
		return
	end
	
	local cfg = soundTable[SoundGroupId.Gather][soundtype]
	if cfg and cfg[GatherAction.Lock] then
		SoundUtil.FinalPlaySound(cfg[GatherAction.Lock])	
		return
	end
	
end

