function SoundUtil.PlayGatherSound(gatherId)
	local soundtype = GetTableNumber(TableName.PVETriggerGather, gatherId, 'soundtype')
	if soundtype <= 0 then
		return 
	end
	
	local cfg = soundTable[SoundGroupId.Gather][soundtype]
	if cfg and cfg[GatherAction.Unlock] then
		SoundUtil.FinalPlaySound(cfg[GatherAction.Unlock])
