--sceneSoundSubType:SceneSoundSubType枚举
--playType:PlayType枚举，当sceneSoundSubType为BarrelBattle时playType无意义，不使用
--param:sceneSoundSubType为BarrelBattle时指代关卡的id，其他时指代列表循环递增的值
function SoundUtil.PlaySceneMusic(sceneSoundSubType, playType, param)
	local sceneSubGroup = soundTable[SoundGroupId.Scene][sceneSoundSubType]
	if not sceneSubGroup then
		return -1
	end
	if sceneSoundSubType == SceneSoundSubType.BarrelBattle then
		local targetSound = sceneSubGroup[param]
		if not targetSound and sceneSubGroup.RandomRange ~= nil and #sceneSubGroup.RandomRange > 0 then
			local randomLength = #sceneSubGroup.RandomRange
			targetSound = sceneSubGroup.RandomRange[Mathf.Random(1,randomLength)]
		end
		if targetSound then
			return SoundUtil.FinalPlaySound(targetSound)
		end
		return
	end
	playType = playType == nil and PlayType.Sequence or playType
	local sounds_of_playType = sceneSubGroup[playType]
	if not sounds_of_playType or #sounds_of_playType == 0 then
		Logger.LogError('SoundUtil:PlaySceneMusic error! Guide no sounds of target play type ' .. tostring(playType))
		return -1
	end
	local targetSound = nil
	if playType == PlayType.None then
		_,targetSound = next(sounds_of_playType)
	elseif playType == PlayType.Sequence then
		local seqLength = #sounds_of_playType
		local increaseParam = param or 1
		local key = increaseParam % seqLength
		key = key == 0 and seqLength or key
		targetSound = sounds_of_playType[key]
	elseif playType == PlayType.Random then
		local randomLength = #sounds_of_playType
		local key = Mathf.Random(1,randomLength)
		targetSound = sounds_of_playType[key]
	end
	if targetSound then
		return SoundUtil.FinalPlaySound(targetSound)
	end
end

