-- 播放一个道具音效
-- action表示操作道具的具体动作
function SoundUtil.PlayItemEffect(itemId, action)
	
	-- 首先进行itemId匹配
	local cfg = soundTable[SoundGroupId.Item][itemId]
	if cfg and cfg[action] then
		SoundUtil.FinalPlaySound(cfg[action])
		return
	end
	
	-- 然后进行soundgroup处理
	local itemSoundGroupId = CommonUtil.GetSoundGroupId(itemId)
	if itemSoundGroupId then
		cfg = soundTable[SoundGroupId.Item][-itemSoundGroupId]
		if cfg and cfg[action] then
			SoundUtil.FinalPlaySound(cfg[action])
			return
		end
	end
	
	-- 播放一个默认的声音
	cfg = soundTable[SoundGroupId.Item][0]
	if cfg and cfg[action] then
		SoundUtil.FinalPlaySound(cfg[action])
		return
	end
end

