local WorldScopeVolume = 1.0    --当前WorldScope音组的Volume值

---SetWorldScopeMute
---@param mute boolean
function SoundUtil.SetWorldScopeVolume(volume)
	if WorldScopeVolume == volume then
		return
	end
	Logger.Log("SoundUtil SetWorldScopeVolume " .. tostring(volume))
	WorldScopeVolume = volume
	CS_Sound:ChangeVolume(SoundGround.WorldScope, WorldScopeVolume, CS_Sound.PlayWorldScopeEffect and 0 or 0.2)
end

---ResetWorldScopeMute
function SoundUtil.ResetWorldScopeMute()
	WorldScopeVolume = 1.0;
	CS_Sound:ChangeVolume(SoundGround.WorldScope, WorldScopeVolume, CS_Sound.PlayWorldScopeEffect and 0 or 0.2)
end

local worldScopeVolumeEffect = {}
---PlayWorldScopeVolumeEffect
---@param effect_name string 特效名称
---@param random_index number 随机尾数（如果有）
---@return number
function SoundUtil.PlayWorldScopeVolumeEffect(effect_name, random_index)
	if random_index then
		effect_name = effect_name .. math.random(1, random_index)
	end

	local serverTimeS = UITimeManager:GetInstance():GetServerSeconds()
	local playTimes = worldScopeVolumeEffect[effect_name] 
	if playTimes == nil then
		worldScopeVolumeEffect[effect_name] = serverTimeS
	else
		if serverTimeS - playTimes > 0.1 then
			worldScopeVolumeEffect[effect_name] = serverTimeS
		else
			return
		end
	end
	
	if CS_Sound.PlayWorldScopeEffect ~= nil then
		return CS_Sound:PlayWorldScopeEffect(_ToID(effect_name))
	else
		return CS_Sound:PlayEffect(_ToID(effect_name), false, WorldScopeVolume, _ToID(SoundGround.WorldScope))
	end
end

