function SoundUtil:SetupAudioMixer()
	local groups = {
		[SoundGround.Music] = SoundGround.Music,
		[SoundGround.Effect] = SoundGround.Effect,
		[SoundGround.Dub] = SoundGround.Dub,
		[SoundGround.Hero] = SoundGround.Dub,
		[SoundGround.WorldScope] = SoundGround.Effect,
	}
	local GameObject = CS.UnityEngine.GameObject
	local CS_AudioMixer = typeof(CS.UnityEngine.Audio.AudioMixer)
	local CS_AudioSource = typeof(CS.UnityEngine.AudioSource)

	local function callback(req, groupName, mixerName)
		if req == nil or req.asset == nil then
			return
		end

		local asset = req.asset
		cast(asset, CS_AudioMixer)

		local tf = GameObject.Find(string.format('SoundComponent/SoundGroup_%s', groupName))
		if tf == nil then
			return
		end

		local audioSource = tf:GetComponent(CS_AudioSource)
		if audioSource == nil then
			return
		end

		local mg = asset:FindMatchingGroups('Master')
		if mg ~= nil and mg.Length > 0 then
			audioSource.outputAudioMixerGroup = mg[0]
		end
	end

	for groupName, mixerName in pairs(groups) do
		local assetReq = CS.GameEntry.Resource:LoadAssetAsync(string.format('Assets/Main/Sound/Mixer/%s.mixer', mixerName), CS_AudioMixer)
		if assetReq ~= nil then
			assetReq:completed('+', function(req)
				callback(req, groupName, mixerName)
			end)
		end
	end
end

function SoundUtil.__setEffectMuteRuntime(isMute)
	for _, groupName in pairs(SoundGround) do
		if groupName ~= SoundGround.Music then
			CS_Sound:SetSoundGroupMute(groupName, isMute)
		end
	end
end


function SoundUtil.SetEffectMutePersistent(isMute)
	SoundUtil.__setEffectMuteRuntime(isMute)
	Setting:SetPublicBool(SettingKeys.EFFECT_MUSIC_ON, not isMute)
end

function SoundUtil.MuteAllSoundTemporary()
	CS_Sound:SetSoundGroupMute(SoundGround.Music, true)
	SoundUtil.__setEffectMuteRuntime(true)
end

function SoundUtil.RecoverAllSoundMuteState()
	local bgIsMute = not Setting:GetPublicBool(SettingKeys.BG_MUSIC_ON, true)
	local effectIsMute = not Setting:GetPublicBool(SettingKeys.EFFECT_MUSIC_ON, true)

	CS_Sound:SetSoundGroupMute(SoundGround.Music, bgIsMute)
	SoundUtil.__setEffectMuteRuntime(effectIsMute)
end


return ConstClass("SoundUtil", SoundUtil)
